--
-- Name: placement_stats_pg; Type: TABLE; Schema: public; Owner: nitkkr
--

CREATE TABLE public.placement_stats_pg (
    id smallint NOT NULL,
    academic_session text NOT NULL,
    discipline text NOT NULL,
    programme text NOT NULL,
    number_of_eligible smallint NOT NULL,
    number_of_placed smallint NOT NULL,
    median_package numeric(8,3) NOT NULL,
    average_package numeric(8,3) NOT NULL,
    lowest_package numeric(8,3) NOT NULL,
    highest_package numeric(8,3) NOT NULL,
    percentage_placed numeric(7,4) GENERATED ALWAYS AS (
CASE
    WHEN (number_of_eligible = 0) THEN (0)::numeric
    ELSE (((number_of_placed)::numeric / (number_of_eligible)::numeric) * (100)::numeric)
END) STORED,
    number_of_offers smallint NOT NULL,
    number_of_internship smallint NOT NULL,
    number_of_ppo smallint NOT NULL,
    total_number_of_placed smallint NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.placement_stats_pg OWNER TO nitkkr;

